import React from 'react';

const smallChopsData = [
  {
    id: 1,
    name: "The Starter Mark",
    price: "15,000",
    contents: "7 Samosas, 7 Spring rolls, 15 Puff Puff, 10 Mosa (or 5 Money Bags), 4 Chicken",
    image: "https://images.unsplash.com/photo-1601050690597-df056fb47045?auto=format&fit=crop&w=400&q=80" 
  },
  {
    id: 2,
    name: "Signature Platter",
    price: "25,000",
    contents: "A luxury high-volume curation. Perfect for gifting, office meetings, or premium sharing.",
    image: "https://images.unsplash.com/photo-1541529086526-db283c563270?auto=format&fit=crop&w=400&q=80" 
  },
  {
    id: 3,
    name: "Owambe Platter",
    price: "150,000",
    contents: "Full Event Catering service for 50 People. The ultimate party selection for luxury gatherings.",
    image: "https://images.unsplash.com/photo-1555939594-58d7cb561ad1?auto=format&fit=crop&w=400&q=80" 
  },
  {
    id: 4,
    name: "Customized Platter",
    price: "200,000",
    contents: "Bespoke catering tailored to your specific guest list and cravings. Starts at ₦200k.",
    image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=400&q=80" 
  }
];

function Menu() {
  return (
    <section style={{ backgroundColor: '#000', color: '#fff', padding: '80px 20px' }}>
      
      <h2 style={{ 
        color: '#D4AF37', 
        textAlign: 'center', 
        letterSpacing: '10px', 
        textTransform: 'uppercase', 
        fontSize: '1.8rem', 
        marginBottom: '60px',
        fontWeight: '300'
      }}>
        The Collections
      </h2>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', 
        justifyContent: 'center', 
        gap: '30px', 
        maxWidth: '1300px', 
        margin: '0 auto' 
      }}>
        
        {smallChopsData.map((pack) => (
          <div key={pack.id} style={{ 
            backgroundColor: '#0A0A0A', 
            borderRadius: '0px', // Square edges look more "high-end"/minimalist
            overflow: 'hidden', 
            border: '1px solid #1A1A1A',
            display: 'flex',
            flexDirection: 'column'
          }}>
            
            <div style={{ width: '100%', height: '240px', overflow: 'hidden' }}>
                <img 
                src={pack.image} 
                alt={pack.name} 
                style={{ width: '100%', height: '100%', objectFit: 'cover', filter: 'brightness(0.7) contrast(1.1)' }} 
                />
            </div>

            <div style={{ padding: '25px', flexGrow: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
              <div>
                <h3 style={{ color: '#D4AF37', fontSize: '1.4rem', marginBottom: '15px', textTransform: 'uppercase', letterSpacing: '2px' }}>
                  {pack.name}
                </h3>
                
                <p style={{ 
                  color: '#ccc', 
                  fontSize: '0.85rem', 
                  lineHeight: '1.6',
                  marginBottom: '25px',
                  borderLeft: '1px solid #E07A5F',
                  paddingLeft: '15px'
                }}>
                  {pack.contents}
                </p>
              </div>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <p style={{ color: '#fff', fontSize: '1.4rem', fontWeight: 'bold', margin: 0 }}>
                  {pack.id === 4 ? "Starts ₦" : "₦"}{pack.price.toLocaleString()}
                </p>
                
                <button style={{ 
                  backgroundColor: 'transparent', 
                  color: '#D4AF37', 
                  border: '1px solid #D4AF37', 
                  padding: '10px 20px', 
                  fontSize: '0.7rem', 
                  fontWeight: 'bold',
                  textTransform: 'uppercase',
                  letterSpacing: '2px',
                  cursor: 'pointer'
                }}>
                  Book Now
                </button>
              </div>
            </div>
          </div>
        ))}

      </div>
    </section>
  );
}

export default Menu;
